sql:
SELECT AVG(social_capital) AS average_social_capital, efficacy
FROM community_resilience
WHERE efficacy = (SELECT MAX(efficacy) FROM community_resilience);

SELECT AVG(age) AS average_age, MAX(risk_perception) AS max_risk_perception
FROM community_resilience
WHERE damage_experience = 1;

SELECT age, education
FROM community_resilience
WHERE damage_experience = 1;

SELECT rural, AVG(efficacy) AS avg_efficacy, COUNT(*) AS total_individuals
FROM community_resilience
GROUP BY rural;

SELECT social_level 
FROM social_capitals 
WHERE social_id = 1;

SELECT COUNT(*) AS education_count, AVG(efficacy) AS average_efficacy
FROM community_resilience
WHERE education = (SELECT MIN(education) FROM community_resilience);

external_knowledge:
- Basic education level is assumed to correspond to education_id = 1; 
- Fundamental knowledge of tornadoes is assumed to correspond to knowledge_id = 1; 
- Low-risk perception is assumed to correspond to risk_perception_level_id = 1 in the community resilience data.

